import React from 'react';
import { Button } from 'react-bootstrap';

function CreateDeckBtn() {
    return(
        <Button variant="secondary" size="large" className="m-2 d-flex justify-content-center flex-direction-row">
        <PlusSquare className="m-1" size={25} />
        <h4>Create Deck</h4>
      </Button>
    )
}

export default CreateDeckBtn;
